// TG-137: Fetch all daily briefing data in one code node
const supabaseUrl = $vars.TG_SUPABASE_URL ? `${$vars.TG_SUPABASE_URL}/rest/v1` : 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = $vars.TG_SUPABASE_ANON_KEY || '';
const serviceKey = $vars.TG_SUPABASE_SERVICE_KEY || supabaseKey;
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${serviceKey}`
};

const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
const todayStr = now.toISOString().slice(0, 10);

// 1. New leads (last 24h)
let leads = [];
try {
  leads = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/leads?created_at=gte.${yesterday}&select=id,first_name,last_name,name,source,phone,email,created_at,lead_score,lead_tier&order=created_at.desc`,
    headers: supabaseHeaders
  });
} catch (e) { leads = []; }

// 2. Pending follow-ups (follow_up_stage > 0 and < 5)
let followUps = [];
try {
  followUps = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/leads?follow_up_stage=gt.0&follow_up_stage=lt.5&lead_tier=neq.converted&select=id,first_name,last_name,name,follow_up_stage`,
    headers: supabaseHeaders
  });
} catch (e) { followUps = []; }

// 3. Today's scheduled jobs
let jobs = [];
try {
  jobs = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/jobber_email_events?event_type=eq.job_scheduled&parsed_scheduled_date=eq.${todayStr}&select=id,customer_name,service_name,parsed_scheduled_time`,
    headers: supabaseHeaders
  });
} catch (e) { jobs = []; }

// 4. Weather for Madison WI (free, no key)
let weather = null;
try {
  weather = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://wttr.in/Madison+WI?format=j1',
    headers: { 'Accept': 'application/json' }
  });
} catch (e) { weather = null; }

// 5. Recent Google reviews (last 24h)
let reviews = [];
try {
  reviews = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/google_reviews?created_at=gte.${yesterday}&select=id,author_name,rating,text,created_at`,
    headers: supabaseHeaders
  });
} catch (e) { reviews = []; }

// 6. All reviews for overall stats
let allReviews = [];
try {
  allReviews = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/google_reviews?select=id,rating`,
    headers: supabaseHeaders
  });
} catch (e) { allReviews = []; }

// 7. n8n system health
let errors = [];
let activeWorkflows = 0;
try {
  const n8nKey = $vars.TG_N8N_API_KEY || 'N8N_API_KEY_PLACEHOLDER';
  const errResp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://tgyardcare.app.n8n.cloud/api/v1/executions?limit=50&status=error',
    headers: { 'X-N8N-API-KEY': n8nKey }
  });
  errors = (errResp && errResp.data) ? errResp.data : (Array.isArray(errResp) ? errResp : []);
  // Filter to last 24h
  errors = errors.filter(e => {
    try { return new Date(e.startedAt || e.createdAt) >= new Date(yesterday); }
    catch(ex) { return false; }
  });
} catch (e) { errors = []; }

try {
  const n8nKey = $vars.TG_N8N_API_KEY || 'N8N_API_KEY_PLACEHOLDER';
  const wfResp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://tgyardcare.app.n8n.cloud/api/v1/workflows?active=true&limit=100',
    headers: { 'X-N8N-API-KEY': n8nKey }
  });
  activeWorkflows = (wfResp && wfResp.data) ? wfResp.data.length : 0;
} catch (e) { activeWorkflows = 0; }

return [{
  json: {
    leads: Array.isArray(leads) ? leads : [],
    followUps: Array.isArray(followUps) ? followUps : [],
    jobs: Array.isArray(jobs) ? jobs : [],
    weather,
    reviews: Array.isArray(reviews) ? reviews : [],
    allReviews: Array.isArray(allReviews) ? allReviews : [],
    errors,
    activeWorkflows
  }
}];

// TG-137: Build formatted Telegram briefing message
const data = $input.first().json;

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', {
  timeZone: 'America/Chicago',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

// Weather section
let weatherSection = '';
if (data.weather && data.weather.current_condition && data.weather.current_condition[0]) {
  const w = data.weather.current_condition[0];
  const tempF = w.temp_F || '?';
  const desc = (w.weatherDesc && w.weatherDesc[0]) ? w.weatherDesc[0].value : 'Unknown';
  const forecast = data.weather.weather && data.weather.weather[0] ? data.weather.weather[0] : null;
  const high = forecast ? forecast.maxtempF : '?';
  const low = forecast ? forecast.mintempF : '?';
  const hourly = forecast && forecast.hourly ? forecast.hourly : [];
  const maxRain = hourly.length > 0 ? Math.max(...hourly.map(h => parseInt(h.chanceofrain || '0'))) : 0;
  weatherSection = `${tempF}\u00b0F ${desc} | High ${high}\u00b0F Low ${low}\u00b0F\nRain: ${maxRain}%`;
  if (maxRain > 60) weatherSection += `\n\u26a0\ufe0f Rain likely \u2014 check outdoor schedule`;
  if (parseInt(tempF) < 32) weatherSection += `\n\u2744\ufe0f Below freezing`;
} else {
  weatherSection = 'Unavailable';
}

// Leads section
const leads = data.leads || [];
let leadsList = '';
if (leads.length > 0) {
  leadsList = leads.slice(0, 8).map(l => {
    const name = l.name || `${l.first_name || ''} ${l.last_name || ''}`.trim() || 'Unknown';
    const source = l.source || '?';
    const tierEmoji = l.lead_tier === 'hot' ? '\ud83d\udd25' : l.lead_tier === 'warm' ? '\ud83d\udfe1' : '\ud83d\udd35';
    const score = l.lead_score || 0;
    return `  ${tierEmoji} ${name} \u2014 ${source} \u2014 score ${score}`;
  }).join('\n');
  if (leads.length > 8) leadsList += `\n  ... and ${leads.length - 8} more`;
} else {
  leadsList = '  None';
}
const followUps = data.followUps || [];

// Schedule section
const jobs = data.jobs || [];
let jobsList = '';
if (jobs.length > 0) {
  jobsList = jobs.slice(0, 5).map(j => {
    const cust = j.customer_name || 'Unknown';
    const svc = j.service_name || '';
    const time = j.parsed_scheduled_time || '';
    return `  \ud83d\udee0 ${cust}${svc ? ' \u2014 ' + svc : ''}${time ? ' @ ' + time : ''}`;
  }).join('\n');
  if (jobs.length > 5) jobsList += `\n  ... and ${jobs.length - 5} more`;
} else {
  jobsList = '  No jobs scheduled';
}

// Reviews section
const reviews = data.reviews || [];
const allReviews = data.allReviews || [];
let reviewsList = '';
if (reviews.length > 0) {
  reviewsList = reviews.slice(0, 3).map(r => {
    const stars = '\u2b50'.repeat(Math.min(r.rating || 0, 5));
    const snippet = r.text ? r.text.substring(0, 60) + (r.text.length > 60 ? '...' : '') : '';
    return `  ${stars} ${r.author_name || 'Anonymous'}${snippet ? '\n    "' + snippet + '"' : ''}`;
  }).join('\n');
}
let overallReview = '';
if (allReviews.length > 0) {
  const avg = (allReviews.reduce((s, r) => s + (r.rating || 0), 0) / allReviews.length).toFixed(1);
  overallReview = `Overall: ${avg} avg (${allReviews.length} total)`;
}

// Errors section
const errors = data.errors || [];
let errorDetails = '';
if (errors.length > 0) {
  const errorNames = [...new Set(errors.map(e => e.workflowData?.name || e.workflowId || 'unknown'))];
  errorDetails = errorNames.slice(0, 3).map(n => `  \u274c ${n}`).join('\n');
}

// Build message
const lines = [
  `\ud83d\udcca TOTALGUARD DAILY BRIEFING`,
  dateStr,
  '',
  `\ud83c\udf24 WEATHER`,
  weatherSection,
  '',
  `\ud83d\udce5 LEADS (${leads.length} new)`,
  leadsList,
  `Pending follow-ups: ${followUps.length}`,
  '',
  `\ud83d\udcc5 TODAY'S SCHEDULE`,
  `${jobs.length} job${jobs.length !== 1 ? 's' : ''} scheduled`,
  jobsList,
  '',
  `\u2b50 REVIEWS (${reviews.length} new)`,
  reviews.length > 0 ? reviewsList : '  None',
  overallReview,
  '',
  `\ud83d\udda5 SYSTEM HEALTH`,
  `Active workflows: ${data.activeWorkflows || '?'}`,
  `Errors (24h): ${errors.length}`,
  errorDetails,
  '',
  `\u2615 Have a great day!`
];

return [{ json: { message: lines.filter(l => l !== undefined && l !== '').join('\n') } }];
